package com.app.uniqueplant.data.datasource.local
import androidx.room.RoomDatabase
import androidx.sqlite.db.SupportSQLiteDatabase
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.launch

class AppDatabaseCallback(
    private val database: AppDatabase
) : RoomDatabase.Callback() {
    override fun onCreate(db: SupportSQLiteDatabase) {
        super.onCreate(db)
        CoroutineScope(Dispatchers.IO).launch {
            database.personTypeDao().insertDefaultPersonTypes()
        }
    }
}

package com.app.uniqueplant.data.datasource.local
import androidx.room.RoomDatabase
import androidx.sqlite.db.SupportSQLiteDatabase
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.launch
import javax.inject.Inject
import javax.inject.Provider

class AppDatabaseCallback private constructor() : RoomDatabase.Callback() {

    private lateinit var database: Provider<AppDatabase>

    override fun onCreate(db: SupportSQLiteDatabase) {
        super.onCreate(db)
        CoroutineScope(Dispatchers.IO).launch {
            database.get().personTypeDao().insertDefaultPersonTypes()
        }
    }

    class Factory @Inject constructor() {
        @Inject
        lateinit var databaseProvider: Provider<AppDatabase>

        fun create(): AppDatabaseCallback {
            val callback = AppDatabaseCallback()
            callback.database = databaseProvider
            return callback
        }
    }
}
